import React from 'react';
import { useNavigate } from 'react-router-dom';

const Landing = () => {
    const navigate = useNavigate();

    const handleRoleSelect = (role) => {
        navigate(`/login?role=${role}`);
    };

    return (
        <div className="landing-container">
            <div className="landing-overlay"></div>
            <div className="landing-content slide-up">
                <div className="landing-header">
                    <div className="logo pulse-animation" style={{ fontSize: '4rem', marginBottom: '1rem' }}>🏥</div>
                    <h1 className="gradient-text" style={{ fontSize: '3.5rem', marginBottom: '0.5rem' }}>Disease Predictor AI</h1>
                    <p style={{ fontSize: '1.2rem', color: '#e2e8f0', maxWidth: '600px', margin: '0 auto 3rem auto' }}>
                        Empowering patients with preemptive health insights and equipping clinicians with 
                        advanced diagnostic intelligence.
                    </p>
                </div>

                <h2 style={{ color: 'white', marginBottom: '2rem' }}>Choose your portal</h2>

                <div className="role-cards-container">
                    <div className="role-card patient-card glass-panel" onClick={() => handleRoleSelect('patient')}>
                        <div className="role-icon">👩‍⚕️</div>
                        <h3>Patient Portal</h3>
                        <p>Track your vitals, check symptoms, and consult with our AI Health Assistant.</p>
                        <button className="btn-primary glow-btn" style={{ marginTop: 'auto' }}>Enter as Patient</button>
                    </div>

                    <div className="role-card doctor-card glass-panel" onClick={() => handleRoleSelect('doctor')}>
                        <div className="role-icon">🩺</div>
                        <h3>Doctor Portal</h3>
                        <p>Access cohort analytics, predictive alerts, and AI-generated clinical reporting.</p>
                        <button className="btn-secondary" style={{ marginTop: 'auto', background: 'rgba(255,255,255,0.1)', color: 'white' }}>Enter as Clinician</button>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Landing;
